{
  "病情摘要": "2型糖尿病8年，近期血糖控制不佳：空腹8.5-10.2 mmol/L，餐后12-15 mmol/L，糖化血红蛋白8.6%。自述漏服晚餐前降糖药，饮食中晚餐主食偏多，运动减少。无胸闷气促、无多饮多尿加重、双足偶有麻木无破溃。血压132/78 mmHg尚在可接受范围。",
  "依从性": {
    "用药": "评估：偶尔忘记晚餐前口服降糖药，依从性部分良好。建议：设置手机闹钟或使用药盒提醒；如漏服，按药品说明书处理（通常可补服，但避免下次加倍剂量），不自行调整药物。",
    "饮食运动": "评估：饮食控制不佳（晚餐主食偏多），运动量减少（因照顾孙子）。建议：减少精制碳水摄入（如白米饭、面条），增加蔬菜比例；每日进行30分钟中等强度运动（如散步、家务），避免久坐。",
    "复诊检查": "未提及近期复诊或检查，建议补充信息或安排糖化血红蛋白复查（目标<7%）及全面体检。"
  },
  "居家监测": {
    "项目": ["空腹血糖", "餐后2小时血糖", "体重", "足部感觉"],
    "频率": "空腹和餐后血糖：每日监测（尤其在调整期间）；体重：每周一次；足部：每日检查",
    "目标": "个体化目标；一般成人空腹4.4-7.0 mmol/L，餐后<10.0 mmol/L，HbA1c<7%。但需结合年龄、并发症等由医生制定。",
    "记录要求": "详细记录每次血糖值、饮食内容（尤其碳水化合物种类和量）、运动情况、用药时间及剂量，便于分析原因并调整方案。"
  },
  "风险分层": {
    "级别": "中风险",
    "依据": ["空腹血糖持续>7.0 mmol/L", "餐后血糖>10.0 mmol/L", "糖化血红蛋白8.6%高于控制目标", "偶发漏服降糖药物"]
  },
  "随访建议": {
    "方式": "电话随访后，若血糖未改善则安排门诊复诊",
    "时间": "2周内进行电话随访或门诊复诊",
    "护理措施": ["加强血糖监测频率并记录", "提供具体饮食调整示例（如每餐主食不超过1拳头）", "鼓励每日增加活动量（如分次家务）", "强调药物按时服用的重要性", "指导足部日常检查方法"]
  },
  "需就医/升级条件": ["血糖持续>13.9 mmol/L或<3.9 mmol/L", "出现口渴、多尿、乏力明显加重", "恶心、呕吐、腹痛", "呼吸困难、胸痛", "意识模糊、抽搐", "足部红肿、疼痛、溃疡或感染迹象", "尿量显著减少或水肿加重"],
  "健康教育": ["糖尿病饮食：控制总热量，均衡营养，减少精制糖和脂肪；每餐主食不超过1拳头，增加蔬菜摄入", "规律运动：每周至少150分钟中等强度运动（如快走30分钟/天），避免久坐", "药物管理：按时服用，不自行停药或更改剂量；如漏服，按说明书处理", "自我监测：学会使用血糖仪，记录结果供医生参考", "低血糖识别：心慌、出汗、饥饿时立即测血糖，口服15g糖（如葡萄糖片）", "足部护理：每日检查有无破损、红肿，保持清洁干燥，避免赤脚行走", "定期随访：每3-6个月查糖化血红蛋白，每年眼科（查视网膜）、肾病（查尿蛋白）等专科检查"]
}

{
